scriptContent:
# Chokepoint Web Shells Emulation
# Create web shell marker in test web root, spawn cmd.exe with recon commands, encoded PS
# Expected Detections: EID 11 (file in web path), EID 1 (cmd.exe child)

[CmdletBinding()]
param(
    [switch]$DryRun
)

Write-Host "=== Chokepoint Web Shells Emulation ===" -ForegroundColor Cyan
Write-Host "Emulating web shell persistence and command execution"

# Stage 1: Create web shell marker (EID 11 target)
Write-Host "\n[Stage 1] Creating web shell marker..."
$webRoot = "C:\inetpub\wwwroot"
$testShell = Join-Path $webRoot "test-emulation.aspx"

if (-not $DryRun) {
    try {
        if (-not (Test-Path $webRoot)) {
            New-Item -Path $webRoot -ItemType Directory -Force | Out-Null
            Write-Host "  Created test web root: $webRoot" -ForegroundColor Yellow
        }
        $shellContent = @"
<%@ Page Language="C#" %>
<%
    // Emulation marker - not a real web shell
    Response.Write("Emulation Complete");
%>
"@ | Out-File -FilePath $testShell -Encoding UTF8 -Force
        Write-Host "  Created: $testShell" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 11 (FileCreate in web path)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would create web shell marker at: $testShell" -ForegroundColor Magenta
}

# Stage 2: Spawn cmd.exe with recon commands (EID 1 target)
Write-Host "\n[Stage 2] Spawning cmd.exe with recon commands..."
if (-not $DryRun) {
    try {
        $reconCommands = "whoami /all & net user & net localgroup administrators & ipconfig /all & systeminfo"
        Start-Process cmd.exe -ArgumentList "/c", $reconCommands -Wait -NoNewWindow
        Write-Host "  Action: cmd.exe spawned with reconnaissance commands" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 1 (ProcessCreate - cmd.exe child)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would spawn cmd.exe with recon commands" -ForegroundColor Magenta
}

# Stage 3: Execute encoded PowerShell (EID 1 target)
Write-Host "\n[Stage 3] Executing encoded PowerShell..."
if (-not $DryRun) {
    try {
        $psCommand = "Write-Host 'Web Shell PS Emulation Test'"
        $encoded = [Convert]::ToBase64String([Text.Encoding]::Unicode.GetBytes($psCommand))
        Start-Process powershell.exe -ArgumentList "-EncodedCommand", $encoded -Wait -NoNewWindow
        Write-Host "  Action: Encoded PowerShell executed" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 1 (ProcessCreate with -EncodedCommand)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would execute encoded PowerShell" -ForegroundColor Magenta
}

# Cleanup
Write-Host "\n[Cleanup] Removing emulation artifacts..."
if (-not $DryRun -and (Test-Path $testShell)) {
    Remove-Item -Path $testShell -Force -ErrorAction SilentlyContinue
    Write-Host "  Removed: $testShell" -ForegroundColor Yellow
}

Write-Host "\n=== Emulation Complete ===" -ForegroundColor Cyan
Write-Host "Expected Detections:"
Write-Host "  - EID 11: File creation in web root path" -ForegroundColor Green
Write-Host "  - EID 1: cmd.exe spawned as child process" -ForegroundColor Green
Write-Host "  - EID 1: PowerShell with -EncodedCommand flag" -ForegroundColor Green
